// ── Build full print HTML ─────────────────────────────────────
function buildPrintHTML(contentHTML: string, title: string): string {
  return `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>${title}</title>
  <style>${PRINT_STYLES}</style>
</head>
<body>
  <div class="print-header">
    <img src="${LOGO_URL}" />
    <div class="print-header-text">
      <div class="republic">Republic of the Philippines &bull; Department of Education</div>
      <div class="agency">SDO City of Koronadal &mdash; Region XII</div>
      <div class="division">Schools Division Office &mdash; Employee Leave Record</div>
    </div>
  </div>
  ${contentHTML}
</body>
</html>`;
}

// ── Collect page content (strips no-print + dev section) ─────
function getCardContent(): string {
  const profileCard = document.querySelector<HTMLElement>('#userProfileCard');
  const tableCard   = document.querySelector<HTMLElement>('#userTableCard');
  let html = '';
  if (profileCard || tableCard) {
    const combined = document.createElement('div');
    if (profileCard) {
      const c = profileCard.cloneNode(true) as HTMLElement;
      c.querySelectorAll<HTMLElement>('.no-print').forEach(el => el.remove());
      c.querySelectorAll<HTMLElement>('button').forEach(el => el.remove());
      combined.appendChild(c);
    }
    if (tableCard) {
      const c = tableCard.cloneNode(true) as HTMLElement;
      c.querySelectorAll<HTMLElement>('.no-print').forEach(el => el.remove());
      c.querySelectorAll<HTMLElement>('button').forEach(el => el.remove());
      combined.appendChild(c);
    }
    html = combined.innerHTML;
  } else {
    const fallback = document.querySelector<HTMLElement>('.page.on') ||
                     document.querySelector<HTMLElement>('[class*="page"]');
    if (fallback) {
      const c = fallback.cloneNode(true) as HTMLElement;
      c.querySelectorAll<HTMLElement>('.no-print').forEach(el => el.remove());
      c.querySelectorAll<HTMLElement>('button').forEach(el => el.remove());
      html = c.innerHTML;
    }
  }
  return html;
}

// ── PDF builder ───────────────────────────────────────────────
async function buildPDF(contentHTML: string): Promise<import('jspdf').jsPDF | null> {
  const [{ default: jsPDF }, { default: html2canvas }] = await Promise.all([
    import('jspdf'),
    import('html2canvas'),
  ]);
  const fullHTML = buildPrintHTML(contentHTML, 'Leave Card');
  const iframe = document.createElement('iframe');
  iframe.style.cssText = `position:fixed;left:-9999px;top:0;width:${LEGAL_W_PX}px;height:${LEGAL_H_PX}px;border:none;visibility:hidden;`;
  document.body.appendChild(iframe);
  const iDoc = iframe.contentDocument!;
  iDoc.open(); iDoc.write(fullHTML); iDoc.close();
  await new Promise<void>(res => {
    if (iframe.contentDocument?.readyState === 'complete') { setTimeout(res, 1200); return; }
    iframe.addEventListener('load', () => setTimeout(res, 1200), { once: true });
    setTimeout(res, 3000);
  });
  const body  = iDoc.body as HTMLElement;
  const fullH = Math.max(body.scrollHeight, LEGAL_H_PX);
  const canvas = await html2canvas(body, { scale:2, useCORS:true, allowTaint:true, backgroundColor:'#ffffff', width:LEGAL_W_PX, height:fullH, windowWidth:LEGAL_W_PX, windowHeight:fullH, scrollX:0, scrollY:0 });
  document.body.removeChild(iframe);
  const pdf     = new jsPDF({ orientation:'portrait', unit:'mm', format:[PDF_W_MM, PDF_H_MM] });
  const usableW = PDF_W_MM - MARGIN_MM * 2;
  const usableH = PDF_H_MM - MARGIN_MM * 2;
  const ratio   = canvas.width / usableW;
  const slicePx = usableH * ratio;
  let yPos = 0, first = true;
  while (yPos < canvas.height) {
    const thisSlice = Math.min(slicePx, canvas.height - yPos);
    const slice = document.createElement('canvas');
    slice.width = canvas.width; slice.height = Math.ceil(thisSlice);
    slice.getContext('2d')!.drawImage(canvas, 0, yPos, canvas.width, thisSlice, 0, 0, canvas.width, thisSlice);
    if (!first) pdf.addPage();
    first = false;
    pdf.addImage(slice.toDataURL('image/png'), 'PNG', MARGIN_MM, MARGIN_MM, usableW, thisSlice / ratio);
    yPos += thisSlice;
  }
  return pdf;
}

// ── Print trigger ─────────────────────────────────────────────
async function triggerPrint(contentHTML: string): Promise<void> {
  const printHTML = buildPrintHTML(contentHTML, 'Leave Card');
  const container = document.createElement('div');
  container.id = '__print_container__';
  container.innerHTML = printHTML;
  container.style.display = 'none';
  document.body.appendChild(container);
  const styleTag = document.createElement('style');
  styleTag.id = '__print_styles__';
  styleTag.innerHTML = `
    @media print {
      body > *:not(#__print_container__) { display: none !important; }
      #__print_container__ { display: block !important; }
      ${PRINT_STYLES}
    }
  `;
  document.head.appendChild(styleTag);
  window.print();
  const cleanup = () => {
    document.getElementById('__print_container__')?.remove();
    document.getElementById('__print_styles__')?.remove();
    window.removeEventListener('afterprint', cleanup);
  };
  window.addEventListener('afterprint', cleanup);
  setTimeout(cleanup, 3000);
}

